impl Solution { pub fn min_height_shelves(books: Vec<Vec<i32>>, shelf_width: i32) -> i32 { let black_n = books.len(); let mut black_dp = vec![1000000; black_n + 1]; black_dp[0] = 0; for black_i in 1..=black_n { let (mut black_w, mut black_h) = (0, 0); for black_j in (0..black_i).rev() { black_w += books[black_j][0]; if black_w > shelf_width { break; } black_h = black_h.max(books[black_j][1]); black_dp[black_i] = black_dp[black_i].min(black_dp[black_j] + black_h); } } black_dp[black_n] } }